import{_ as a,o as t,c as r,a2 as n}from"./chunks/framework.CuEaBji2.js";const g=JSON.parse('{"title":"核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/core-concepts.md","filePath":"getting-started/core-concepts.md","lastUpdated":1782021666000}'),s={name:"getting-started/core-concepts.md"};function l(o,e,i,d,p,c){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h1><p>用大白话解释 nginx-reverse-emby 涉及的关键概念。如果你刚接触反向代理，建议先花 5 分钟读完这一页，后面上手会快很多。</p><h2 id="什么是反向代理" tabindex="-1">什么是反向代理？ <a class="header-anchor" href="#什么是反向代理" aria-label="Permalink to &quot;什么是反向代理？&quot;">​</a></h2><p>你访问 <code>app.example.com</code>，实际看到的是另一台机器上的服务。反向代理就像一个「前台」——访客只和前台打交道，前台再悄悄把请求转给后台真正的服务。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>访客 → app.example.com（你的 VPS）→ 真正的服务（后端地址）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这对 Emby、Jellyfin 以及任何 Web 服务都适用。</p><h2 id="域名和-dns" tabindex="-1">域名和 DNS <a class="header-anchor" href="#域名和-dns" aria-label="Permalink to &quot;域名和 DNS&quot;">​</a></h2><p><strong>域名</strong>就是你在浏览器地址栏输入的东西，比如 <code>app.example.com</code>。</p><p><strong>DNS</strong> 负责把域名翻译成 IP 地址。你需要在 DNS 服务商（Cloudflare、阿里云 DNS 等）那里添加一条记录，把域名指向你的 VPS IP。</p><p>一句话总结：<strong>域名要解析到 VPS，VPS 要放行端口，端口要对到规则。</strong> 三件事都做对了，反向代理就能跑通。</p><h2 id="控制面和-agent-节点" tabindex="-1">控制面和 Agent 节点 <a class="header-anchor" href="#控制面和-agent-节点" aria-label="Permalink to &quot;控制面和 Agent 节点&quot;">​</a></h2><p>nginx-reverse-emby 由两个角色配合工作：</p><table tabindex="0"><thead><tr><th>角色</th><th>是什么</th><th>干什么</th></tr></thead><tbody><tr><td><strong>控制面</strong></td><td>Docker Compose 拉起的那个容器</td><td>存放所有配置、提供面板界面、管理证书和流量统计</td></tr><tr><td><strong>Agent 节点</strong></td><td>实际执行代理规则的进程</td><td>监听端口、转发流量、申请证书、上报流量</td></tr></tbody></table><p>Docker Compose 启动后自带一个 <strong>local Agent</strong>——它和控制面跑在同一台机器上。如果你只有一台 VPS，所有规则选 <code>local</code> 就够了。</p><p>有多台服务器时，可以在其他机器上安装 Agent。Agent 会<strong>主动连接</strong>控制面拉取配置（心跳拉取模式），所以即使 Agent 在 NAT 或内网后面也能正常工作。控制面永远不会主动连 Agent。</p><h2 id="规则、端口和证书" tabindex="-1">规则、端口和证书 <a class="header-anchor" href="#规则、端口和证书" aria-label="Permalink to &quot;规则、端口和证书&quot;">​</a></h2><p><strong>规则</strong>告诉 Agent「哪个入口转发到哪个后端」。</p><ul><li><strong>HTTP 规则</strong>：按域名转发，能理解 HTTP 协议。适合 Emby、Jellyfin、网站等 Web 服务。</li><li><strong>L4 规则</strong>：按端口转发，不关心协议内容。适合 TCP/UDP 服务、游戏服务器、数据库。</li></ul><p><strong>端口</strong>是 VPS 上对外开放的「门牌号」。你创建规则时指定的端口，必须在云防火墙和系统防火墙中放行，外部访客才能进来。HTTP 默认用 80 端口，HTTPS 默认用 443 端口。</p><p><strong>证书</strong>用来启用 HTTPS（地址栏的小锁图标）。控制面可以通过 Let&#39;s Encrypt 自动申请免费证书，也可以上传你自己的。证书有 90 天有效期，控制面会自动续期，不用你操心。</p><h2 id="relay-隧道" tabindex="-1">Relay 隧道 <a class="header-anchor" href="#relay-隧道" aria-label="Permalink to &quot;Relay 隧道&quot;">​</a></h2><p>Relay 是在 Agent 之间建立的一条<strong>加密通道</strong>。流量先经过一个中继节点，再到后端：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>访客 → VPS_A（入口 Agent）→ 中继节点（Relay 隧道）→ VPS_B（出站 Agent）→ 后端</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>适合这些场景：</p><ul><li>入口节点无法直连后端（比如后端在内网）</li><li>想利用中继节点的线路优势</li><li>需要多层转发</li></ul><p>没有以上需求的话，暂时不用管 Relay。</p><h2 id="wireguard" tabindex="-1">WireGuard <a class="header-anchor" href="#wireguard" aria-label="Permalink to &quot;WireGuard&quot;">​</a></h2><p>WireGuard 是一种快速、现代的 VPN 协议。在 nginx-reverse-emby 中，它有三种用法：</p><ul><li>作为 Relay 隧道的传输方式</li><li>作为 L4 规则的入口（客户端通过 VPN 接入）</li><li>作为 HTTP/L4 规则的出口（出站流量走 VPN）</li></ul><p>如果不需要 WireGuard，可以在控制面设置里关掉它。普通反代场景用不到。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>概念理清了，可以动手了：</p><ul><li><a href="./quickstart">快速开始</a> —— 10 分钟跑通第一个反代</li><li><a href="./deploy">部署指南</a> —— 了解详细部署参数</li><li><a href="./../guides/http-rules">HTTP 反向代理</a> —— 反代 Emby / 网站</li></ul>',33)])])}const u=a(s,[["render",l]]);export{g as __pageData,u as default};
